INSERT INTO `behavior_records` VALUES ('0438d1d9-d32b-4b1f-9aa8-2e31fd8f720d','10006','45a1704b-b35f-46ee-bdcd-3b25a735dea4','2026-04-25','พบพฤติกรรม: เอาชายเสื้อออกนอกกางเกง กระโปรง (เครื่องแบบนักเรียนไทยพุทธ) บริเวณโรงอาหาร','2567d140-8dad-40ad-812b-5a17556e765a','อนุมัติแล้ว','ทำงานสาธารณประโยชน์','2026-06-15 07:34:04','2026-06-15 07:34:04'),('141373a0-2511-4ba0-9fbe-a50ea9ac2f7f','10003','499f38de-0ddd-4583-b536-6ae4fe1e50c5','2026-05-02','พบพฤติกรรม: ใช้เครื่องประดับตกแต่งร่างกาย ใบหน้าอย่างไม่เหมาะสม บริเวณโรงอาหาร','941c0e24-0744-485d-87af-67f3eaa3523c','รออนุมัติ','ทำงานสาธารณประโยชน์','2026-06-15 07:34:04','2026-06-15 07:34:04'),('155f97cf-a55b-4305-b95a-050f664298e0','10005','da675c38-35b8-428f-b61e-5a5d74bba73c','2026-05-08','พบพฤติกรรม: ลักขโมยและมีส่วนร่วมในการลักขโมยของผู้อื่นมาเป็นตนโดยเจตนา บริเวณสนาม','941c0e24-0744-485d-87af-67f3eaa3523c','อนุมัติแล้ว',NULL,'2026-06-15 07:34:04','2026-06-15 07:34:04'),('15d03ff9-6c54-490a-8b9d-3c834b85440f','10004','3a708ff2-b5a3-4203-afcb-0ed6c6012666','2026-05-18','พบพฤติกรรม: กล่าวเท็จ ช่วยเหลือ ปกปิด ผู้กระทำความผิดอันเกิดความเสียหายต่อผู้อื่นและส่วนรวม บริเวณโรงอาหาร','2567d140-8dad-40ad-812b-5a17556e765a','อยู่ในระหว่างโต้แย้ง','ทำความสะอาด','2026-06-15 07:34:04','2026-06-15 07:34:04'),('1c0c5daa-f576-45d3-9fd5-e6936ecd9069','10002','af0c4548-dfc3-4d8b-ab8f-99b191919a60','2026-04-28','พบพฤติกรรม: ไม่สำรวมกิริยามารยาท นอกบริเวณโรงเรียนขณะอยู่ในเครื่องแบบนักเรียน บริเวณห้องเรียน','941c0e24-0744-485d-87af-67f3eaa3523c','อนุมัติแล้ว','ทำงานสาธารณประโยชน์','2026-06-15 07:34:04','2026-06-15 07:34:04'),('1c5b7b39-becb-4f84-b377-446b214d53c4','10004','fb90562b-2908-4ee9-b691-b42e7a59c5f6','2026-05-17','นักเรียนแสดงพฤติกรรมที่ดี: ช่วยเหลือเพื่อน/ผู้อื่น','941c0e24-0744-485d-87af-67f3eaa3523c','อนุมัติแล้ว',NULL,'2026-06-15 07:34:04','2026-06-15 07:34:04'),('313572ce-9e4e-4bd1-8ec4-ab22c4c1f66f','10001','df3cc611-5f14-42b2-9c74-b0619f814465','2026-04-26','พบพฤติกรรม: หลีกเลี่ยงการปฏิบัติกิจกรรมหน้าเสาธงในตอนเช้า บริเวณ